final:
module RefModule(
    input clk,
    input rst,

    output reg [1:0] gray_q
);

reg [1:0] unused_binary_q;  // Internal binary counter

// Gray Code Counter logic
always @(posedge clk) begin
    if (rst)
        unused_binary_q <= 2'b00;
    else
        unused_binary_q <= unused_binary_q + 1;
end

// Convert binary counter to Gray code
always @(unused_binary_q) begin
    gray_q = unused_binary_q ^ (unused_binary_q >> 1);
end

endmodule
